// Queue Error Handler — marks the currently-running queue item as failed/retry/cooldown
// Receives error context from Error Trigger (execution.id, execution.error)
// ADR-042: Cooldown requeue — after max_retries, delay 24h instead of permanent fail.
// Permanent fail only after MAX_COOLDOWN_CYCLES (3) cooldown cycles = 12 total attempts.

const errorData = $input.first().json;
const executionId = errorData.execution && errorData.execution.id;
const errorMessage = (errorData.execution && errorData.execution.error && errorData.execution.error.message) || 'Unknown error';

const url = $env.SUPABASE_URL;
const key = $env.SUPABASE_SERVICE_KEY;
const headers = {
  apikey: key,
  Authorization: 'Bearer ' + key,
  'Content-Type': 'application/json'
};

const MAX_COOLDOWN_CYCLES = 3;
const COOLDOWN_HOURS = 24;

console.log('Queue Error Handler: execution ' + executionId + ' failed: ' + errorMessage);

const cutoff = new Date(Date.now() - 60 * 60 * 1000).toISOString();
const running = await this.helpers.httpRequest({
  method: 'GET',
  url: url + '/rest/v1/pipeline_queue',
  qs: {
    status: 'eq.running',
    started_at: 'gte.' + cutoff,
    select: 'id,metro_name,retry_count,max_retries,run_id,cooldown_count',
    order: 'started_at.desc',
    limit: 1
  },
  headers: { apikey: key, Authorization: 'Bearer ' + key },
  json: true
});

if (!running || running.length === 0) {
  console.log('Queue Error Handler: no running queue items found');
  return [{ json: { step: 'queue_error_handler', status: 'no_running_items', error: errorMessage } }];
}

const item = running[0];
const newRetryCount = (item.retry_count || 0) + 1;
const maxRetries = item.max_retries || 3;
const cooldownCount = item.cooldown_count || 0;

var updateBody = { error_message: errorMessage };
var logStatus = '';

if (newRetryCount < maxRetries) {
  // Fast retry — try again on next schedule cycle
  updateBody.status = 'pending';
  updateBody.retry_count = newRetryCount;
  updateBody.started_at = null;
  logStatus = 'pending (retry ' + newRetryCount + '/' + maxRetries + ')';
} else if (cooldownCount < MAX_COOLDOWN_CYCLES) {
  // Cooldown requeue — reset retry count, wait 24h, then retry
  var retryAfter = new Date(Date.now() + COOLDOWN_HOURS * 60 * 60 * 1000).toISOString();
  updateBody.status = 'pending';
  updateBody.retry_count = 0;
  updateBody.cooldown_count = cooldownCount + 1;
  updateBody.retry_after = retryAfter;
  updateBody.started_at = null;
  logStatus = 'pending (cooldown ' + (cooldownCount + 1) + '/' + MAX_COOLDOWN_CYCLES + ', retry_after: ' + retryAfter + ')';
} else {
  // Permanent failure — exhausted all retries and cooldown cycles
  updateBody.status = 'failed';
  updateBody.retry_count = newRetryCount;
  updateBody.completed_at = new Date().toISOString();
  logStatus = 'failed (exhausted ' + MAX_COOLDOWN_CYCLES + ' cooldown cycles)';
}

await this.helpers.httpRequest({
  method: 'PATCH',
  url: url + '/rest/v1/pipeline_queue',
  qs: { id: 'eq.' + item.id },
  headers: { ...headers, Prefer: 'return=minimal' },
  body: updateBody,
  json: true
});

console.log('Queue Error Handler: ' + item.metro_name + ' -> ' + logStatus);

if (item.run_id) {
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: url + '/rest/v1/pipeline_runs',
      qs: { id: 'eq.' + item.run_id },
      headers: { ...headers, Prefer: 'return=minimal' },
      body: {
        status: 'failed',
        completed_at: new Date().toISOString(),
        errors: [errorMessage]
      },
      json: true
    });
    console.log('  pipeline_runs ' + item.run_id + ' -> failed');
  } catch(e) {
    console.log('  WARNING: failed to mark pipeline_runs: ' + e.message);
  }
}

return [{ json: {
  step: 'queue_error_handler',
  metro_name: item.metro_name,
  queue_id: item.id,
  run_id: item.run_id,
  new_status: updateBody.status,
  retry_count: updateBody.retry_count,
  max_retries: maxRetries,
  cooldown_count: updateBody.cooldown_count || cooldownCount,
  retry_after: updateBody.retry_after || null,
  error: errorMessage
} }];
